const now = new Date();
const d7 = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const iso = now.toISOString();
const runDate = iso.slice(0, 10);
const isMonday = now.getUTCDay() === 1;
return [{ json: { now: iso, since7d: d7.toISOString(), runDate, isMonday } }];

function rows(nodeName, idKey = 'id') {
  const out = [];
  for (const it of $(nodeName).all()) {
    const p = it && it.json;
    if (!p) continue;
    if (Array.isArray(p)) { for (const r of p) if (r && typeof r === 'object' && (idKey === null || r[idKey])) out.push(r); }
    else if (Array.isArray(p.data)) { for (const r of p.data) if (r && typeof r === 'object' && (idKey === null || r[idKey])) out.push(r); }
    else if (typeof p === 'object' && (idKey === null || p[idKey])) { out.push(p); }
  }
  return out;
}

const snapshots = rows('Read platform_snapshots', 'snapshot_date');
const opps = rows('Read revenue_opportunities');
const highTasks = rows('Read high compliance_tasks');
const meta = $('Compute Window').first().json;

const latest = snapshots[0] || null;
const prev = snapshots[1] || null;

// Top opps by estimated monthly revenue
const top10 = opps
  .filter(o => typeof o.estimated_aud_monthly === 'number')
  .sort((a, b) => (b.estimated_aud_monthly || 0) - (a.estimated_aud_monthly || 0))
  .slice(0, 10);

const hasData = !!latest;

if (!hasData) {
  return [{ json: {
    bypass_claude: true,
    digest: {
      headline: 'CEO daily — no platform_snapshots available yet',
      note: 'Data aggregator has not written its first snapshot yet. Digest is a heartbeat only.',
      run_date: meta.runDate,
    },
    run_at: meta.now,
  }}];
}

const system = [
  'You are the CEO Agent for invest.com.au. You run once a day at 06:00 Sydney and produce a short founder digest.',
  'Per the spec: ≤ 400 words daily, ≤ 600 words on Mondays. Decisions > AUD $500 require ceo_approvals rows — you do NOT commit spend in the digest itself.',
  'Your job is to surface the most valuable next action across revenue / compliance / migration / product.',
  'Cite numbers only where the snapshot supports them. Do NOT invent metrics. When data is missing, say so explicitly.',
  '',
  'Return a JSON block (```json ... ```) with keys: headline (<=120 chars), top_priority (one string <=240 chars), top_3_opportunities (array of 3 strings referencing revenue_opportunities by id where useful), flags (array of strings for compliance/risk items), recommended_actions (array of 3 strings, each addressed to an agent by number or to Fin). Follow the JSON block with one plain-English line.',
].join('\n');

const user = [
  `Run at: ${meta.now} (Monday weekly-brief mode: ${meta.isMonday})`,
  '',
  'Latest platform_snapshots row (source of truth):',
  '```json',
  JSON.stringify({ snapshot_date: latest.snapshot_date, metrics: latest.metrics }, null, 2),
  '```',
  '',
  'Previous day snapshot (for trend context, may be null):',
  '```json',
  JSON.stringify(prev ? { snapshot_date: prev.snapshot_date, metrics: prev.metrics } : null, null, 2),
  '```',
  '',
  'Top 10 revenue_opportunities by estimated_aud_monthly:',
  '```json',
  JSON.stringify(top10, null, 2),
  '```',
  '',
  'High/critical compliance_tasks (open):',
  '```json',
  JSON.stringify(highTasks.slice(0, 20), null, 2),
  '```',
].join('\n');

return [{ json: {
  bypass_claude: false,
  system,
  user,
  snapshot_date: latest.snapshot_date,
  top10_opp_ids: top10.map(o => o.id),
  high_task_count: highTasks.length,
  run_at: meta.now,
  runDate: meta.runDate,
  isMonday: meta.isMonday,
}}];

const resp = $json || {};
const meta = $('Build CEO prompt').item.json;

const textBlocks = Array.isArray(resp.content) ? resp.content.filter(c => c && c.type === 'text').map(c => c.text || '') : [];
const combined = textBlocks.join('\n');

let parsed = null;
const fence = combined.match(/```json\s*([\s\S]*?)```/i);
if (fence) { try { parsed = JSON.parse(fence[1].trim()); } catch (e) { parsed = null; } }
if (!parsed) {
  const brace = combined.match(/\{[\s\S]*\}/);
  if (brace) { try { parsed = JSON.parse(brace[0]); } catch (e) { parsed = null; } }
}

const headline = (parsed && typeof parsed.headline === 'string') ? parsed.headline.slice(0, 240) : 'CEO daily digest';
const top_priority = (parsed && typeof parsed.top_priority === 'string') ? parsed.top_priority.slice(0, 600) : null;
const top_3_opportunities = (parsed && Array.isArray(parsed.top_3_opportunities)) ? parsed.top_3_opportunities.slice(0, 3).map(s => String(s).slice(0, 400)) : [];
const flags = (parsed && Array.isArray(parsed.flags)) ? parsed.flags.slice(0, 5).map(s => String(s).slice(0, 400)) : [];
const recommended_actions = (parsed && Array.isArray(parsed.recommended_actions)) ? parsed.recommended_actions.slice(0, 3).map(s => String(s).slice(0, 400)) : [];

// Severity derived from inputs, not Claude.
let level = 'info';
if (meta.high_task_count > 0 || flags.length > 0) level = 'warn';

return [{ json: {
  agent_name: 'ceo',
  level,
  message: headline,
  metadata: {
    daily_digest: true,
    snapshot_date: meta.snapshot_date,
    is_monday: meta.isMonday,
    ceo: {
      headline, top_priority, top_3_opportunities, flags, recommended_actions,
      raw_text: combined.slice(0, 4000),
      model: resp.model || 'claude-opus-4-7',
      stop_reason: resp.stop_reason,
      usage: resp.usage,
    },
    top10_opp_ids: meta.top10_opp_ids,
    run_at: meta.run_at,
  },
}}];
